import React, { useRef, useState } from "react";
import { BrowserRouter as Router, Routes, Route, Navigate, useLocation } from "react-router-dom";
import Navbar from "./components/Navbar";
import Home from "./components/Home";
import About from "./components/About";
import PracticeAreas from "./components/PracticeAreas";
import Professionals from "./components/Professionals";
import News from "./components/News";
import Gallery from "./components/Gallery";
import Contact from "./components/Contact";
import AllNews from "./components/AllNews";
import Login from "./components/Login";
import AdminDashboard from "./components/AdminDashboard";
import Messages from "./components/admin/Messages";
import InviteAdmin from "./components/admin/InviteAdmin"; // Add this import
import "./styles.css";

function App() {
  const [auth, setAuth] = useState({
    isAuthenticated: false,
    user: null
  });
  const newsSectionRef = useRef(null);
  const location = useLocation();

  const scrollToNewsSection = () => {
    if (newsSectionRef.current) {
      newsSectionRef.current.scrollIntoView({ behavior: "smooth" });
    }
  };

  // Check if current route is an admin route
  const isAdminRoute = location.pathname.startsWith('/admin');

  return (
    <>
      {/* Hide Navbar for all admin routes */}
      {!isAdminRoute && <Navbar auth={auth} setAuth={setAuth} />}

      <Routes>
        {/* Static Routes */}
        <Route
          path="/"
          element={
            <>
              <section id="HOME"><Home /></section>
              <section id="ABOUT US"><About /></section>
              <section id="AREAS OF PRACTICE"><PracticeAreas /></section>
              <section id="OUR PROFESSIONALS"><Professionals /></section>
              <section id="NEWS & ARTICLES" ref={newsSectionRef}><News /></section>
              <section id="GALLERY"><Gallery /></section>
              <section id="CONTACT US"><Contact /></section>
            </>
          }
        />

        {/* News Routes */}
        <Route path="/news" element={<Navigate to="/#NEWS & ARTICLES" replace />} />
        <Route path="/more-news" element={<AllNews scrollToNewsSection={scrollToNewsSection} />} />

        {/* Admin Routes */}
        <Route path="/admin/login" element={
          auth.isAuthenticated ? <Navigate to="/admin/dashboard" /> : <Login setAuth={setAuth} />
        } />

        <Route path="/admin/dashboard" element={
          auth.isAuthenticated ? <AdminDashboard user={auth.user} /> : <Navigate to="/admin/login" />
        } />

        <Route path="/admin/messages" element={
          auth.isAuthenticated ? <Messages auth={auth} setAuth={setAuth} /> : <Navigate to="/admin/login" />
        } />

        {/* Add the Invite Admin route */}
        <Route path="/admin/invite" element={
          auth.isAuthenticated && auth.user?.role === "SuperAdmin" ? 
            <InviteAdmin auth={auth} setAuth={setAuth} /> : 
            <Navigate to={auth.isAuthenticated ? "/admin/dashboard" : "/admin/login"} />
        } />

        {/* 404 Route */}
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </>
  );
}

export default function Root() {
  return (
    <Router>
      <App />
    </Router>
  );
}
